from abc import ABC, abstractmethodimport cv2import numpy as npimport pyautoguiclass ActionTrigger(ABC):    """blueprint for the computer whenever I want to trigger an action"""    @abstractmethod    def execute(self):        passclass ScrollableActionTrigger(ActionTrigger):    def execute(self):        pyautogui.scroll(-200)        print("\033[1;31m RED IS DETECTED: SCROLLING DOWN\033[0m")class VisionController(ABC):    @abstractmethod    def process_frame(self,frame):        passclass RedObjectController(VisionController):    def __init__ ( self,action_trigger: ActionTrigger, camera_index=0):        #Encapsulation        self.__cap = cv2.VideoCapture(camera_index, cv2.CAP_DSHOW)        self.__action_trigger = action_trigger        self._prev_y = 0        self.__red_lower1 = np.array([0,120,70])        self.__red_upper1 = np.array([10,255,255])        self.__red_lower2 = np.array([170,120,70])        self.__red_upper2 = np.array([180,255,255])    @property    def ia_camera_ready(self):        return self.__cap.isOpened()    def process_frame(self, frame):        blurred = cv2.GaussianBlur(frame, (11,11), 0)        hsv = cv2.cvtColor(blurred, cv2.COLOR_BGR2HSV)        mask1 = cv2.inRange(hsv, self.__red_lower1, self.__red_upper1)        mask2 = cv2.inRange(hsv, self.__red_lower2, self.__red_upper2)        mask = cv2.bitwise_or(mask1, mask2)        mask =cv2.erode(mask, None, iterations=2)        mask =cv2.dilate(mask, None, iterations=2)        